subsection.codeblock:
interfaces {
    irb {
        unit 419 {
            family inet {
                address 10.104.19.3/24;
            }
            family inet6 {
                address 2419::3/64;
            }
        }
    }
    ens4f1 {
        unit 0 {
            family bridge {
                interface-mode trunk;
                vlan-id-list [ 100 200 400 414-423 500 ];
            }
        }
    }
}

routing-instances {
    vswitch {
        instance-type virtual-switch;
        bridge-domains {
            bd419 {
                vlan-id 419;
                routing-interface irb.419;
            }
        }
        interface ens4f1;
    }
}

routing-instances {
    blue19 {
        instance-type vrf;
        protocols {
            bgp {
                group ce_pe_19_v4 {
                    type external;
                    local-address 10.104.19.3;
                    peer-as 1002;       
                    local-as 64512;
                    bfd-liveness-detection {
                        minimum-interval 300;
                    }
                    neighbor 10.104.19.4;
                }
                group ce_pe_19_v6 {
                    type external;
                    local-address 2419::3;
                    peer-as 1002;
                    local-as 64512;
                    bfd-liveness-detection {
                        minimum-interval 300;
                    }
                    neighbor 2419::4;
                }
            }
            evpn {
                ip-prefix-routes {
                    advertise direct-nexthop;
                    encapsulation vxlan;
                    vni 2019;
                    export vrf_route_19;
                }
            }
        }
        interface irb.419;
        interface lo0.19;
        route-distinguisher 100.100.100.1:2019;
        vrf-target target:20:2019;
    }
}
